```C#
using Microsoft.AspNetCore.Mvc;

[Route("api/invoice")]
public class InvoiceController : ControllerBase
{
    private readonly IInvoiceService _invoiceService;
    
    public InvoiceController(IInvoiceService invoiceService)
    {
        _invoiceService = invoiceService;
    }
    
    [HttpGet("{id}")]
    public ActionResult<InvoiceDetail> GetInvoiceDetails(string id)
    {
        var invoice = _invoiceService.GetInvoiceById(id);
        
        if (invoice == null)
            return NotFound();
            
        return Ok(invoice);
    }
}
``` 

This code snippet represents an ASP.NET Core API endpoint which provides the invoice details by invoice ID. It uses dependency injection to get access to InvoiceService instance through IInvoiceService interface. The invoice is retrieved using GetInvoiceById method from the injected service. If no such invoice exists, a 404 Not Found response is returned; otherwise - an OK (200) response with the found invoice as its content.